                head1 = head1->next;
            }

            if (head2) {
                sum += head2->data;
                head2 = head2->next;
            }

            carry = sum / 10;
            curr->next = new Node(sum % 10);
            curr = curr->next;
        }

        Node* result = reverse(dummy->next);

        // 🔥 REMOVE LEADING ZEROS
        while (result && result->data == 0 && result->next) {
            result = result->next;
        }

