class Solution {
  public:
    bool check(vector<int>&arr, int k, int mid){
        int number=1, pages=0;
        for(int i=0;i<arr.size();i++){
            if(arr[i]>mid) return false;
            if(pages+arr[i]>mid){
                pages=arr[i];
                number++;
            }
            else{
                pages+=arr[i];
            }
        }
        if(number<=k) return true;
        return false;
    }

    int findPages(vector<int> &arr, int k) {
        // code here
        if(arr.size()<k) return -1;
        int lo=0, hi=0;
        for(auto it:arr) hi+=it;
        int ans=-1;
        while(lo<=hi){
            int mid=(lo+hi)/2;
            if(check(arr, k, mid)){
                ans=mid;
                hi=mid-1;
            }
            else{
                lo=mid+1;
            }
        }
        return ans;
    }
};

class Solution {
  public:

    void rearrange(vector<int> &arr) {
        // code here
        vector<int> pos,neg;
        for(auto i:arr){
            if(i>=0) pos.push_back(i);
            else neg.push_back(i);
        }
        arr.clear();

        while(!pos.empty() && !neg.empty()){
            arr.push_back(*pos.begin());
            pos.erase(pos.begin());
            arr.push_back(*neg.begin());
            neg.erase(neg.begin());
        }

        while(!pos.empty()){
            arr.push_back(*pos.begin());
            pos.erase(pos.begin());
        }

        while(!neg.empty()){
            arr.push_back(*neg.begin());
            neg.erase(neg.begin());
        }

    }
};

