class Solution {
  public:

   Node *buildBSTFromInorder(vector<int> &inorder, int start, int end){
      if (start > end)
      {
        return nullptr;
      }

      int mid = (start + end) / 2;
      Node *node = new Node(inorder[mid]);

      node->left = buildBSTFromInorder(inorder, start, mid - 1);
      node->right = buildBSTFromInorder(inorder, mid + 1, end);

      return node;
    }

    Node* sortedArrayToBST(vector<int>& nums) {
        Node *root = buildBSTFromInorder(nums, 0, nums.size() - 1);
        return root;
    }
};

class Solution {
  public:
  void dfs(int node, int parent, vector<int> adj[], vector<int>& vis,
             vector<int>& tin, vector<int>& low, int& timer,
             vector<int>& mark) {

        vis[node] = 1;
        tin[node] = low[node] = timer++;
        int child = 0;

        for (auto it : adj[node]) {
            if (it == parent) continue;

            if (!vis[it]) {
                dfs(it, node, adj, vis, tin, low, timer, mark);
                low[node] = min(low[node], low[it]);

                // Articulation condition
                if (low[it] >= tin[node] && parent != -1) {
                    mark[node] = 1;
                }

                child++;
            } else {
                // back edge
                low[node] = min(low[node], tin[it]);
            }
        }

        // root node case
        if (parent == -1 && child > 1) {
            mark[node] = 1;
        }
    }

    vector<int> articulationPoints(int V, vector<vector<int>>& edges) {
        // Code here
        vector<int> adj[V];

        // Build graph
        for (auto &e : edges) {
            adj[e[0]].push_back(e[1]);
            adj[e[1]].push_back(e[0]);
        }

        vector<int> vis(V, 0), tin(V), low(V), mark(V, 0);
        int timer = 0;

        // Handle disconnected graph
        for (int i = 0; i < V; i++) {
            if (!vis[i]) {
                dfs(i, -1, adj, vis, tin, low, timer, mark);
            }
        }

        vector<int> ans;
        for (int i = 0; i < V; i++) {
            if (mark[i]) ans.push_back(i);
        }

        if (ans.size() == 0) return {-1};
        return ans;
    }
};

class Solution {
public:
    int timer;
    void dfs(int u, vector<int>& disc, vector<int>& low, vector<int>& parent, vector<vector<int>>& adj, vector<bool>& ap) {
        disc[u] = low[u] = timer++;
        int children = 0;

        for (int v : adj[u]) {
            if (disc[v] == -1) { // Not visited
                parent[v] = u;
                children++;
                dfs(v, disc, low, parent, adj, ap);

                low[u] = min(low[u], low[v]);

                // Case 1: u is root of DFS tree and has two or more children
                if (parent[u] == -1 && children > 1)
                    ap[u] = true;

                // Case 2: u is not root and low[v] >= disc[u]
                if (parent[u] != -1 && low[v] >= disc[u])
                    ap[u] = true;
            }
            else if (v != parent[u]) {
                // Back edge
                low[u] = min(low[u], disc[v]);
            }
        }
    }

    vector<int> articulationPoints(int V, vector<vector<int>>& edges) {
        vector<vector<int>> adj(V);
        for (auto& edge : edges) {
            int u = edge[0], v = edge[1];
            adj[u].push_back(v);
            adj[v].push_back(u); // undirected
        }

        vector<int> disc(V, -1), low(V, -1), parent(V, -1);
        vector<bool> ap(V, false);
        timer = 0;

        for (int i = 0; i < V; i++) {
            if (disc[i] == -1) {
                dfs(i, disc, low, parent, adj, ap);
            }
        }

        vector<int> result;
        for (int i = 0; i < V; i++) {
            if (ap[i])
                result.push_back(i);
        }

        if (result.empty()) return {-1};
        return result;
    }
};

