class Solution {
  public:
    string binaryNextNumber(string s) {
        // code here.
        reverse(s.begin(), s.end());
        int carry=1;
        for(int i=0;i<s.length() && carry==1;i++){
            if(s[i]=='0'){
                s[i]='1';
                carry=0;
            }
            else{
                s[i]='0';
                carry=1;
            }
        }
        if(carry){
            s=s+'1';
        }
        reverse(s.begin(), s.end());
        int idx=0;
        while(s[idx]=='0'){
            idx++;
        }
        int n=s.length();
        return s.substr(idx,n-idx);
    }
};

class Solution {
  public:
    Node *head = nullptr, *prev = nullptr;

    // Function to convert binary tree to doubly linked list and return the head.
    Node* bToDLL(Node* root) {
        bToDLLUtil(root);
        return head;
    }

    // Utility function to perform in-order traversal and link nodes.
    void bToDLLUtil(Node* root) {
        if (root == nullptr) {
            return;
        }

        // Recur on the left subtree.
        bToDLLUtil(root->left);

        // If head is null, this is the first node.
        if (head == nullptr) {
            head = prev = root;
        } else {
            // Link the previous node with the current node.
            prev->right = root;
            root->left = prev;
            prev = root;
        }

        // Recur on the right subtree.
        bToDLLUtil(root->right);
    }
};

