class Solution {
  public:
    map<pair<int, int>, vector<int>> mp;
    int countWays(string &s) {
        // code here
        return solve(0, s.length() - 1, s, true);
    }
    int solve(int i, int j, string &s, bool iTN) {
        if (i > j) {
            // invalid
            return 0;
        }
        if (i == j) {
            return (s[i] == 'T') == iTN ? 1 : 0;
        }
        pair<int, int> key = {i, j};
        if (mp.find(key) != mp.end()) {
            return iTN ? mp[key][0] : mp[key][1];
        }
        int trueCount = 0;
        int falseCount = 0;
        for (int k = i + 1; k <= j - 1; k = k + 2)
        {

            int leftTrue = solve(i, k-1, s, true);
            int leftFalse = solve(i, k-1, s, false);
            int rightTrue = solve(k + 1, j, s, true);
            int rightFalse = solve(k + 1, j, s, false);

            switch (s[k])
            {
                case '&':
                {
                    trueCount += leftTrue * rightTrue;
                    falseCount += leftTrue * rightFalse + leftFalse * rightTrue + leftFalse * rightFalse;
                    break;
                }
                case '|':
                {
                    trueCount += leftTrue * rightTrue + leftTrue * rightFalse + leftFalse * rightTrue;
                    falseCount += leftFalse * rightFalse;
                    break;
                }
                case '^':
                {
                    trueCount += leftTrue * rightFalse + leftFalse * rightTrue;
                    falseCount += leftTrue * rightTrue + leftFalse * rightFalse;
                    break;
                }
            }
        }
        mp[key] = {trueCount, falseCount};
        return iTN ? trueCount : falseCount;

    }
};

class Solution{ 
public: 

    int solve(int n,string &s,int i,int j,bool need,vector<vector<vector<int>>>&dp){ 
        // the parenthesis at i means just in the lhs of the the ith index 
        if(i+1==j){ 
            if(need==false){ 
                return (s[i]=='F')?1:0; 
            } 
            else{ 
                return (s[i]=='F')?0:1; 
            } 
        } 
        if(i>j){ 
            return 0; 
        } 

        if(dp[i][j][need]!=-1){ 
            return dp[i][j][need]; 
        } 
        int ans = 0; 
        for(int k = i+1;k<j;k+=2){ 
            if(s[k]=='^'){ 
                if(need==true){ 
                    int ct1 = solve(n,s,i,k,true,dp);//1 
                    int ct2 = solve(n,s,k+1,j,false,dp);//1 
                    int ct3 = solve(n,s,i,k,false,dp);//0 
                    int ct4 = solve(n,s,k+1,j,true,dp);//0 
                    ans = ans + ct1*ct2 + ct3*ct4; 
                } 
                else{ 
                    int ct1 = solve(n,s,i,k,true,dp); 
                    int ct2 = solve(n,s,k+1,j,true,dp); 
                    int ct3 = solve(n,s,i,k,false,dp); 
                    int ct4 = solve(n,s,k+1,j,false,dp); 
                    ans = ans + ct1*ct2 + ct3*ct4; 
                } 
            } 
            else if(s[k]=='|'){ 
                if(need==true){ 
                    int ct1 = solve(n,s,i,k,true,dp); 
                    int ct2 = solve(n,s,k+1,j,false,dp); 
                    int ct3 = solve(n,s,k+1,j,true,dp); 

                    int ct4 = solve(n,s,i,k,false,dp); 
                    int ct5 = solve(n,s,i,k,true,dp); 
                    int ct6 = solve(n,s,k+1,j,true,dp); 
                    ans = ans + ct1*ct2+ct1*ct3+ct6*ct4; 
                } 
                else{ 
                    int ct1 = solve(n,s,i,k,false,dp);//1 
                    int ct2 = solve(n,s,k+1,j,false,dp);//1 
                    ans = ans + ct1*ct2; 
                } 
            } 
            else{ 
                if(need == true){ 
                    int ct1 = solve(n,s,i,k,true,dp); 
                    int ct2 = solve(n,s,k+1,j,true,dp); 
                    ans = ans + ct1*ct2; 
                } 
                else{ 
                    int ct1 = solve(n,s,i,k,true,dp); 
                    int ct2 = solve(n,s,k+1,j,false,dp); 

                    int ct4 = solve(n,s,i,k,false,dp); 
                    int ct5 = solve(n,s,k+1,j,true,dp); 
                    ans = ans + ct1*ct2 + ct4*ct5 + ct4*ct2; 
                } 
            } 
        } 
        return dp[i][j][need] = (ans%1003); 
    } 
    int countWays(int n, string s){ 
        vector<vector<vector<int>>>dp(n+1,vector<vector<int>>(n+1,vector<int>(2,-1))); 
        return solve(n,s,0,s.size(),true,dp); 
    } 
};

class Solution {
  public:
    vector <int> bottomView(Node *root) {
        vector<int> ans;
        if(!root) return ans;
        map<int, int> mp;
        queue<pair<Node*, int>> q;
        q.push({root, 0});

        while(!q.empty()){
            auto temp = q.front();
            q.pop();
            Node* node = temp.first;
            int level = temp.second;

            mp[level] = node->data;
            if(node->left){
                q.push({node->left, level-1});
            }
            if(node->right){
                q.push({node->right, level+1});
            }
        }
        for(auto it: mp){
            ans.push_back(it.second);
        }
        return ans;
    }
};

class Solution {
  private:
    string build(int i, int j, vector<vector<int>> &split) {
        if (i == j) return string(1, 'A' + i);
        int k = split[i][j];
        return "(" + build(i, k, split) + build(k + 1, j, split) + ")";
    }

public:
    string matrixChainOrder(vector<int> &arr) {
        int n = arr.size();
        int m = n - 1; // number of matrices

        vector<vector<long long>> dp(m, vector<long long>(m, 0));
        vector<vector<int>> split(m, vector<int>(m, -1));

        // gap strategy
        for (int len = 2; len <= m; len++) {
            for (int i = 0; i + len - 1 < m; i++) {
                int j = i + len - 1;
                dp[i][j] = LLONG_MAX;

                for (int k = i; k < j; k++) {
                    long long cost = dp[i][k] + dp[k+1][j] + 1LL * arr[i] * arr[k+1] * arr[j+1];
                    if (cost < dp[i][j]) {
                        dp[i][j] = cost;
                        split[i][j] = k;
                    }
                }
            }
        }

        return build(0, m - 1, split);
    }
};

class Solution{ 
public: 
    string matrixChainOrder(int p[], int n){ 

        vector<vector<int>> dp(n, vector<int>(n, 0)); 
        vector<vector<int>> bracket(n, vector<int>(n, 0)); 

        for (int len = 2; len < n; len++) { 
            for (int i = 1; i < n - len + 1; i++) { 
                int j = i + len - 1; 
                dp[i][j] = INT_MAX; 

                for (int k = i; k <= j - 1; k++) { 
                    int cost = dp[i][k] + dp[k + 1][j] + p[i - 1] * p[k] * p[j]; 

                    if (cost < dp[i][j]) { 
                        dp[i][j] = cost; 
                        bracket[i][j] = k; 
                    } 
                } 
            } 
        } 

        return printParenthesis(bracket, 1, n - 1); 
    } 

private: 
    string printParenthesis(const vector<vector<int>>& bracket, int i, int j) { 
        if (i == j) { 
            return string(1, 'A' + i - 1); 
        } 

        return "(" + printParenthesis(bracket, i, bracket[i][j]) + 
               printParenthesis(bracket, bracket[i][j] + 1, j) + ")"; 
    } 
};

