    int maxProfit(vector<int>& arr, int k) {
        int n = arr.size();
        if (n == 0) return 0;

        int cash = 0;           // not holding stock
        int hold = -arr[0];     // holding stock

        for (int i = 1; i < n; i++) {
            int prevCash = cash;

            cash = max(cash, hold + arr[i] - k); // sell
            hold = max(hold, prevCash - arr[i]); // buy
        }

        return cash;
    }
