class Solution {
  public:
    int cntWays(vector<int>& arr) {
        // use prefix sum of odd & even elements
        int n = arr.size();
        int matches = 0;

        // calculate even and odd elements
        int oddSum = 0;
        int evenSum = 0;
        for(int i=0; i<n; i++)
        {
            // i & 1 return true for odd numbers
            if(i & 1)
            {
                oddSum += arr[i];
            }
            else
            {
                evenSum += arr[i];
            }
        }

        // current calculated sum
        int curOdd = 0;
        int curEven = 0;
        for(int i=0; i<n; i++)
        {
            // reduce current element from odd/even sum
            if(i & 1)
            {
                oddSum -= arr[i];
            }
            else
            {
                evenSum -= arr[i];
            }

            // check if current sum + rest of the sum match
            if( curOdd + evenSum == curEven + oddSum)
            {
                matches++;
            }

            // add current element to cur odd/even
            if(i & 1)
            {
                curOdd += arr[i];
            }
            else
            {
                curEven += arr[i];
            }
        }

        return matches;
    }
};

class Solution {
public:

    long long merge(vector<int> &arr, vector<int> &temp,
                    int left, int mid, int right) {

        int i = left;
        int j = mid + 1;
        int k = left;
        long long inv_count = 0;

        while (i <= mid && j <= right) {
            if (arr[i] <= arr[j]) {
                temp[k++] = arr[i++];
            } else {
                temp[k++] = arr[j++];
                inv_count += (mid - i + 1);
            }
        }

        while (i <= mid)
            temp[k++] = arr[i++];

        while (j <= right)
            temp[k++] = arr[j++];

        for (int x = left; x <= right; x++)
            arr[x] = temp[x];

        return inv_count;
    }

    long long mergeSort(vector<int> &arr, vector<int> &temp,
                        int left, int right) {

        long long inv_count = 0;

        if (left < right) {
            int mid = (left + right) / 2;

            inv_count += mergeSort(arr, temp, left, mid);
            inv_count += mergeSort(arr, temp, mid + 1, right);

            inv_count += merge(arr, temp, left, mid, right);
        }

        return inv_count;
    }

    long long inversionCount(vector<int> &arr) {
        int n = arr.size();
        vector<int> temp(n);
        return mergeSort(arr, temp, 0, n - 1);
    }
};

