        unordered_map<int, vector<int>> mp;

        // Store indices of each value
        for(int i = 0; i < arr.size(); i++) {
            mp[arr[i]].push_back(i);
        }

        vector<int> result;

        for(auto &q : queries) {
            int l = q[0];
            int r = q[1];
            int x = q[2];

            if(mp.find(x) == mp.end()) {
                result.push_back(0);
