        Node* fast = head;
        Node* slow = head;

        for (int i = 0; i < n; i++) {
            fast = fast->next;
        }

        while (fast != NULL) {
            fast = fast->next;
            slow = slow->next;
        }

        int sum = 0;
        while (slow != NULL) {
            sum += slow->data;
            slow = slow->next;
        }

        return sum;
    }
