        if(i >= s1.length() || j >= s2.length()){
            return 0;
        }

        if(dp[i][j] != -1){
            return dp[i][j];
        }

        if(s1[i] == s2[j]){
            return dp[i][j] = 1 + lps(s1,s2,i+1,j+1,dp);
        }

        int a1 = lps(s1,s2,i+1,j,dp);
        int a2 = lps(s1,s2,i,j+1,dp);
        return dp[i][j] = max(a1,a2);

    }

