class Solution{
    public:
    static bool comp(Item &a, Item &b){
        return 1.0*a.value/a.weight > 1.0*b.value/b.weight;
    }
    double fractionalKnapsack(int W, Item arr[], int n){
        double profit = 0;
        sort(arr, arr + n, comp);
        for(int i = 0; i < n and W != 0; i++){
            profit += arr[i].value*(1.0*min(arr[i].weight, W)/arr[i].weight);
            W -= min(arr[i].weight, W);
        }
        return profit;
    }
};

class Solution{
public:
    int minValue(string s, int k){
        // code here
        unordered_map<char,int>mp;
        for(int i=0;i<s.length();i++){
            mp[s[i]]++;
        }
        priority_queue<int>pq;
        for(auto it:mp){
            if(it.second!=0){
                pq.push(it.second);
            }
        }
        for(int i=0;i<k;i++){
            int a=pq.top(); pq.pop();
            a--;
            if(a>0){
                pq.push(a);
            }
        }
        int ans=0;
        while(!pq.empty()){
            ans=ans+ pq.top()*pq.top();
            pq.pop();
        }
        return ans;
    }
};

class Solution {
  public:



    int solve(int n, int x, int y, vector<int> &dp)
    {
        if(n <= 1)
            return n;
        if(dp[n] != -1)
            return dp[n];
        int ans = 1;
        if(n >= x)
            ans &= solve(n - x, x, y, dp);
        if(n >= y)
            ans &= solve(n - y, x, y, dp);
        ans &= solve(n - 1, x, y, dp);
        return dp[n] = ans ^ 1;
    }
    int findWinner(int n, int x, int y) {
        vector<int> dp(n + 1, -1);
        return solve(n, x, y, dp);
    }
};

class Solution { 
  public: 
    vector<vector<vector<long long>>> dp; 

    long long findNthNumber(int n, int k) { 
        long long low = 0, high = 1e18; 
        dp = vector<vector<vector<long long>>>(2, vector<vector<long long>>(65, vector<long long>(65, -1))); 
        while(low <= high){ 
            long long mid = low + (high - low) / 2; 
            long long count = find(mid, k); 
            if(count >= n) 
                high = mid - 1; 
            else 
                low = mid + 1; 
        } 
        return low; 
    } 

private: 
    long long find(long long n, int k){ 
        string s = bitset<64>(n).to_string(); 
        reset(); 
        return dpf(s, s.length(), 1, k); 
    } 

    long long dpf(string s, int n, int tight, int k){ 
        if(k < 0) 
            return 0; 
        if(n == 0){ 
            return 1; 
        } 
        if(dp[tight][k][n] != -1) 
            return dp[tight][k][n]; 
        int ub = (tight == 1 ? (int)(s[s.length() - n] - '0') : 1); 
        long long ans = 0; 
        for(int dig = 0; dig <= ub; dig++){ 
            if(dig == ub) 
                ans += dpf(s, n - 1, tight, k - dig); 
            else 
                ans += dpf(s, n - 1, 0, k - dig); 
        } 
        return dp[tight][k][n] = ans; 
    } 

    void reset(){ 
        for(int i = 0; i < 65; i++){ 
            for(int j = 0; j < 65; j++){ 
                dp[0][i][j] = dp[1][i][j] = -1; 
            } 
        } 
    } 
};

class Solution {
