class Solution {
    int[] printKClosest(int[] arr, int n, int k, int x) {
        int id1 = findCrossOver(arr,0,n-1,x);
        int id2 = id1+1;
        if(arr[id1]==x) id1--;
        int ans[] = new int[k];
        for(int i=0;i<k;i++){
            if(id1>=0 && id2<n){
                int val1 = x-arr[id1], val2 = arr[id2]-x;
                if(val1<val2){
                    ans[i] = arr[id1];
                    id1--;
                }else{
                    ans[i] = arr[id2];
                    id2++;        }
            }else if(id1>=0){
                ans[i] = arr[id1];
                id1--;
            }else{
                ans[i] = arr[id2];
                id2++; } }
        return ans;
    }
    private int findCrossOver(int[] arr, int low, int high, int x) {
        if (arr[high] <= x) {
            return high; }
        if (arr[low] > x) {
            return low; }
        int mid = (low + high) / 2;
        if (arr[mid] <= x && arr[mid + 1] > x) {
            return mid;
        } else if (arr[mid] < x) {
            return findCrossOver(arr, mid + 1, high, x);}
        return findCrossOver(arr, low, mid - 1, x);
    }
}

class Solution
{
    public:
    // function should print the nodes at k distance from root
    vector<int> Kdistance(struct Node *root, int k)
    {
      // Your code here
      vector<int>ans;
      int level=0;
      queue<Node*>q;
      q.push(root);

      while(!q.empty()){
          int n=q.size();
          for(int i=0;i<n;i++){
              Node* node=q.front(); q.pop();
              if(level==k) ans.push_back(node->data);

              if(node->left) q.push(node->left);
              if(node->right) q.push(node->right);
          }
          level++;
      }
      return ans;
    }
};

class Solution {
  public:
    vector<int> maxOfSubarrays(vector<int>& arr, int k) {
        // code here
          priority_queue<pair<int,int>>pq;
        int ind = 0;
        vector<int>ans;

        for(int i=0;i<arr.size();i++){
            pq.push({arr[i],i});
            if(i-ind+1 == k){
                while(pq.top().second < ind) pq.pop();
                ans.push_back(pq.top().first);
                ind++;
            }
        }
        return ans;
    }
};

class Solution {
    public ArrayList<Integer> max_of_subarrays(int k, int arr[]) {
        int n = arr.length;
        ArrayList<Integer> ans = new ArrayList<>();
        Deque<Integer> dq = new ArrayDeque<>();

        for(int i=0;i<k;i++){
            while(!dq.isEmpty() && arr[ dq.peekLast() ]<= arr[i]){
                dq.removeLast();
            }

            dq.addLast(i);
        }

        ans.add(arr[ dq.peekFirst() ]);

        for(int i=k;i<n;i++){

            //remove out of window element
            if(dq.peekFirst()<=i-k){
                dq.removeFirst();
            }

            //include current element
            //in decreasing order
            while(!dq.isEmpty() && arr[ dq.peekLast() ]<= arr[i]){
                dq.removeLast();
            }

            dq.addLast(i);

            ans.add(arr[ dq.peekFirst() ]);


        }


        return ans;
    }
}

class Solution {
  public:
    int countPathsUtil(Node* node, int k, int currSum, 
                     unordered_map<int, int>& prefSums) {

    if (node == nullptr)
        return 0;

   int pathCount = 0;
    currSum += node->data;

    if (currSum == k)
        pathCount++;

 // The count of (curr_sum − k) gives the number 
    // of paths with sum k up to the current node
    pathCount += prefSums[currSum - k];

   // Add the current sum into the hashmap
    prefSums[currSum]++;

    pathCount += countPathsUtil(node->left, k, currSum, prefSums);
    pathCount += countPathsUtil(node->right, k, currSum, prefSums);

    // Remove the current sum from the hashmap
    prefSums[currSum]--;

   return pathCount;
}

int countAllPaths(Node* root, int k) {
    unordered_map<int, int> prefSums;

    return countPathsUtil(root, k, 0, prefSums);
}

};

class Solution{
public:
    int lcs(string& s, string& r, int i, int j, vector<vector<int>>&dp){
        if(i<0 || j<0) return 0;
        if(dp[i][j]!=-1) return dp[i][j];

        if(s[i]==r[j]){
            return dp[i][j]=1+lcs(s,r, i-1, j-1, dp);
        }

        return dp[i][j]=max(lcs(s, r, i-1,j,dp), lcs(s,r,i,j-1,dp));
    }

    int kPalindrome(string str, int n, int k)
    {
        // code here
        string r=str;
        reverse(r.begin(), r.end());

        vector<vector<int>>dp(n+1, vector<int>(n+1,-1));

        int x=lcs(str, r, n-1, n-1, dp);

        int rem=n-x;
        return rem<=k;
    }
};

class Solution {
  public:

    bool kPangram(string str, int k) {
        unordered_map<char,int> m;
        int extra=0;

        // calculate the characters present in excess
        for(int i=0;i<str.size();i++)
        {
            if(!isalpha(str[i]))
            {
                continue;
            }
            if(m[str[i]]==1)
            {
                extra++;
            }
            else{
                m[str[i]]=1;
            }
        }

        // calculate the total characters brought in 
        int t=0;
        for(char ch='a';ch<='z';ch++)
        {
            if(extra==0)
            {
                break;
            }

            if(m[ch]==0 && extra>0)
            {
                m[ch]=1;
                extra--;
                t++;
            }
        }

        // check if all the conditions satisfied
        for(char cc='a';cc<='z';cc++)
        {
            if(m[cc]==0)
            {
                return false;
            }
        }
        if(t<=k)
        {
            return true;
        }
        return false;

    }
};

class Solution {
  public:
    int kthElement(vector<int>& a, vector<int>& b, int k) {
        // code here
        int n=a.size(), m=b.size();
        if(n>m) return kthElement(b, a, k);

        int lo=max(0, k-m), hi=min(n, k);
        while(lo<=hi){
            int mid1=(lo+hi)/2;
            int mid2=k-mid1;

            int l1, r1, l2, r2;
            if(mid1==0){
                l1=INT_MIN;
            }
            else{
                l1=a[mid1-1];
            }

            if(mid1==n){
                r1=INT_MAX;
            }
            else{
                r1=a[mid1];
            }

            if(mid2==0){
                l2=INT_MIN;
            }
            else{
                l2=b[mid2-1];
            }

            if(mid2==m){
                r2=INT_MAX;
            }
            else{
                r2=b[mid2];
            }

            if(l1<=r2 && l2<=r1){
                return max(l1,l2);
            }

            if(l1>r2){
                hi=mid1-1;
            }
            else{
                lo=mid1+1;
            }
        }
        return 0;

    }
};

class Solution {
public:
    int kthElement(vector<int> &a, vector<int> &b, int k) {
        int n = a.size();
        int m = b.size();
        if(n > m) return kthElement(b, a, k); // smaller array first

        int low = max(0, k - m);
        int high = min(k, n);

        while(low <= high){
            int mid1 = (low + high)/2;
            int mid2 = k - mid1;

            int l1 = (mid1 > 0) ? a[mid1-1] : INT_MIN;
            int l2 = (mid2 > 0) ? b[mid2-1] : INT_MIN;
            int r1 = (mid1 < n) ? a[mid1] : INT_MAX;
            int r2 = (mid2 < m) ? b[mid2] : INT_MAX;

            if(l1 <= r2 && l2 <= r1) return max(l1, l2);
            else if(l1 > r2) high = mid1 - 1;
            else low = mid1 + 1;
        }
        return -1;
    }
};

class Solution {
  public:
    int kthElement(int k, vector<int>& arr1, vector<int>& arr2) {
         int n1 = arr1.size() , n2 = arr2.size() ;
        if(k == n1+n2)return max(arr1[n1-1],arr2[n2-1]);
        if(k==1)return min(arr1[0],arr2[0]);
        int i = 0 , j = 0 ;
        while(i<n1 && j<n2 && k>1){
            if(arr1[i]<=arr2[j]){
                i++;
            }
            else j++;
            k--;
        }

        while(i<n1 && k>1){
            i++;
            k--;
        }
        while(j<n2 && k>1){
            j++;
            k--;
        }
        if(i==n1)return arr2[j];
        else if(j==n2)return arr1[i];
        return min(arr1[i],arr2[j]);
    }
};

class Solution {
  public:
    // Function to find the sum of contiguous subarray with maximum sum.
    long long maxSubarraySum(vector<int> &arr) {
        long long max_sum = arr[0];
        long long current_sum = arr[0];

        for (int i = 1; i < arr.size(); i++) {
            current_sum = max((long long)arr[i], current_sum + arr[i]);
            max_sum = max(max_sum, current_sum);
        }

        return max_sum;
    }
};

