class Solution {
  public:
    int kokoEat(vector<int>& arr, int k) {
        int n = arr.size();
        int start = 1, end = 1e7, ans = 1e7;
        while(start<=end){
            int mid = start + (end - start)/2, ct = 0;
            for(auto& it:arr){
                ct+=(it+mid-1)/mid;
            }
            if(ct<=k){
                ans = min(ans, mid);
                end = mid-1;
            }else{
                start = mid+1;
            }
        }
        return ans;
    }
};

class Solution {
  public:

    int calculateHours(vector<int>& arr, int rate) {
        int hours = 0;
        for (int bananas : arr) {
            hours += (bananas + rate - 1) / rate; 
        }
        return hours;
    }

    int kokoEat(vector<int>& arr, int k) {
        int low = 1, high = *max_element(arr.begin(), arr.end());
        int result = high;

        while (low <= high) {
            int mid = low + (high - low) / 2;


            int hours = calculateHours(arr, mid);

            if (hours <= k) {

                result = mid;
                high = mid - 1;
            } else {

                low = mid + 1;
            }
        }

        return result;
    }
};

class Solution
{
    public:
    void getParent(Node* root, map<Node*, Node*> &m)
    {
        if(root==NULL) return;
        if(root->left){
            m[root->left] = root;
            getParent(root->left, m);
        }
        if(root->right){
            m[root->right] = root;
            getParent(root->right, m);
        }
    }
    Node* LCA(Node* root, int p, int q){
        if(root==NULL){
            return NULL;
        }
        if(root->data==p){
            return root;
        }
        if(root->data==q){
            return root;
        }
        Node* l = LCA(root->left, p, q);
        Node* r = LCA(root->right, p, q);
        if(l==NULL){
            return r;
        }
        if(r==NULL ){
            return l;
        }
        return root;
    }

    int kthCommonAncestor(Node *root, int k,int x, int y)
    {

        if(root==NULL) return -1;
        Node *lca = LCA(root, x, y);
        map<Node*, Node*> m;
        m[root] = NULL;
        getParent(root, m);
        if(lca==NULL) return -1;
        while(--k){
            lca = m[lca];
            if(lca==NULL) return -1;
        }
        return lca->data;
    }
};

class Solution {
  public:

    bool checkDuplicatesWithinK(vector<int>& arr, int k) {
        unordered_set<int> st;
        for(int i=0; i<arr.size(); i++)
        {
            if(st.find(arr[i]) != st.end())
                return true;
            st.insert(arr[i]);
            if(i >= k)
            {
                st.erase(st.find(arr[i-k]));
            }
        }
        return false;
    }
};

class Solution {
  public:
    int kthMissing(vector<int> &arr, int k) {
        // code here
         int n=arr.size();
        int ans=n;
        int start=0,end=n-1;
        while(start<=end){
            int mid=start+(end-start)/2;
            if(arr[mid]-mid-1>=k){
                ans=mid;
                end=mid-1;
            }
            else
            start=mid+1;

        }
        return ans+k;
    }
};

class Solution {
    public int kthMissing(int[] arr, int k) {
        // code here
        int lo=0, hi = arr.length-1;
        int ans = arr.length + k;
        while(lo <= hi){
            int mid = (lo+hi)/2;
            if(arr[mid] > mid + k){
                hi = mid - 1;
                ans = mid + k;
            }
            else {
                lo = mid + 1;
            }
        }
        return ans;
    }
}

class Solution {
  public:
    int kthSmallest(vector<vector<int>>& mat, int k) {
        int n = mat.size();

        int low = mat[0][0];
        int high = mat[n-1][n-1];
        int ans = low;

        while (low <= high) {
            int mid = low + (high - low) / 2;
            int count = 0;

            // Count elements <= mid
            for (int i = 0; i < n; i++) {
                count += upper_bound(mat[i].begin(), mat[i].end(), mid) - mat[i].begin();
            }

            if (count >= k) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return ans;
    }
};

