class Solution {
  public:
    vector<vector<int>> rotateMatrix(int k, vector<vector<int>> mat) {

        int i=0,j=0;
        int m = mat.size();
        int n = mat[i].size();
        vector<vector<int>>v(m, vector<int>(n));
        for(int i=0; i<m; i++){
            for(int j=0; j<n; j++){
                v[i][(j+n-(k%n))%n] = mat[i][j];
            }
        }
        return v;
    }
};

vector<int> leftView(Node *root)
{
    vector<int> result;
    if(root == NULL) return result;

    queue<Node*> q;
    q.push(root);

    while(!q.empty()) {
        int n = q.size();
        for(int i = 0; i < n; i++) {
            Node* temp = q.front();
            q.pop();
            if(i == 0) result.push_back(temp->data);
            if(temp->left != NULL) q.push(temp->left);
            if(temp->right != NULL) q.push(temp->right);
        }
    }

    return result;
}

class Solution {
  public:
    virtual void dfs(int i, int t, vector<bool> &vis1, vector<bool> &vis2, vector<int> &timer, vector<vector<int>> &adj, int &tans){
      vis1[i]=true; vis2[i]=true; timer[i]=t;

      for(auto x: adj[i]){
        if(!vis1[x]){
          dfs(x, t+1, vis1, vis2, timer, adj, tans);    
        }else if(vis2[x]){
          tans=max(tans, t+1-timer[x]);    
        }  
      }

      vis2[i]=false;
      return;
    }

    virtual int longestCycle(int V, vector<vector<int>>& edges){
      vector<bool> vis1(V+1, false);
      vector<bool> vis2(V+1, false);
      vector<int> timer(V+1, 0);

      vector<vector<int>> adj(V+1);

      for(auto z: edges){
        adj[z[0]].push_back(z[1]);  
      }

      int ans=-1;
      for(int i=0; i<=V; i++){
        if(!vis1[i]){
          int tans=-1;
          dfs(i, 0, vis1, vis2, timer, adj, tans);
          ans=max(ans, tans);
        }  
      }

      return ans;
    }
};

class Solution
{
    public:
    //Function to return the level order traversal of a tree.
    vector<int> levelOrder(Node* root)
    {
      //Your code here
      queue<Node*>q;
      q.push(root);

      vector<int>ans;
      while(!q.empty()){
          Node* node=q.front();
          q.pop();

          ans.push_back(node->data);
          if(node->left){
              q.push(node->left);
          }

          if(node->right){
              q.push(node->right);
          }

      }
      return ans;
    }
};

class Solution {
  public:
    Node* constructLinkedMatrix(vector<vector<int>>& mat) {
        int n=mat.size();
        Node* ans[n][n];
        for(int i=0;i<n;i++){
            for(int j=0;j<n;j++){
                Node* newnode=new Node(mat[i][j]);
                ans[i][j]=newnode;
                if(j>0){
                    ans[i][j-1]->right=ans[i][j];
                }
                if(i>0){
                    ans[i-1][j]->down=ans[i][j];
                }
            }
        }
        return ans[0][0];
    }
};

