class Solution {
public:
    int longestCommonSubstr(string str1, string str2) {
        int n = str1.length();
        int m = str2.length();
        vector<vector<int>> dp(2, vector<int>(m + 1, 0));
        int maxLength = 0;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (str1[i - 1] == str2[j - 1]) {
                    dp[i % 2][j] = dp[(i - 1) % 2][j - 1] + 1;
                    maxLength = max(maxLength, dp[i % 2][j]);
                } else {
                    dp[i % 2][j] = 0;
                }
            }
        }

        return maxLength;
    }
};

class Solution {
  public:

    int longestConsecutive(vector<int>& arr) {

        unordered_set<int> hst(arr.begin(), arr.end());
        int ans = 0;
        for (int i : arr) {
            int curr = 0, tmp = i, tmp2 = i - 1;
            if (hst.count(i)) {
                while (hst.count(tmp)) {
                    curr++;
                    hst.erase(tmp);
                    tmp++;
                }
                while (hst.count(tmp2)) {
                    curr++;
                    hst.erase(tmp2);
                    tmp2--;
                }
            }
            ans = max(ans, curr);
        }
        return ans;
    }
};

class Solution {
  public:
    int lps(string str) {
        long long pre = 0, suf = 0, base = 29, p = 1, ind = 0, n = str.size(), mod = 1e9+7;

        for(int i=0; i<n-1; i++){
            int cha = str[i] - 'a' + 1;
            int chp = str[n-i-1] - 'a' + 1;

            pre = ((pre*base)%mod + cha)%mod;
            suf = (suf + (chp*p)%mod)%mod;

            p=(p*base)%mod;
            if(pre == suf){
                ind = i+1;
            }
        }
        return ind;
    }
};

class Solution {
    int longestPrefixSuffix(String s) {
        int n = s.length();
        int[] lps = new int[n];
        int j = 0; 

        for (int i = 1; i < n; i++) {

            while (j > 0 && s.charAt(i) != s.charAt(j)) {
                j = lps[j - 1]; 
            }
            if (s.charAt(i) == s.charAt(j)) {
                j++;
            }
            lps[i] = j;
        }


        return lps[n - 1] == n ? 0 : lps[n - 1];
    }
}

class Solution {
  public:
    string longestSubstring(string s, int n) {
        // code here

        vector<vector<int>>dp(n+1, vector<int> (n+1,0));

        int mx_length = 0, last = 0;

        for(int i =1; i<= n; i++){

            for(int j = i+1; j<= n; j++){

                if(s[i - 1] == s[j - 1] && dp[i - 1][j-1 ] < (j - i)){

                    dp[i][j] = dp[i -1][j - 1] + 1;

                    if (dp[i][j] > mx_length){

                        mx_length = dp[i][j];

                        last =i-1;
                    }
                }
            }
        }

        if(mx_length == 0){

            return "-1";
        }

        else{
            return s.substr(last - mx_length+1, mx_length);
        }
    }
};

class Solution {
  public:
    int equalSumSpan(vector<int> &a1, vector<int> &a2) {
      int n = a1.size();


        vector<int> first_occurrence(2 * n + 1, -2);

        int max_len = 0;
        int prefix_sum = 0;


        first_occurrence[0 + n] = -1;

        for (int i = 0; i < n; i++) {

            prefix_sum += (a1[i] - a2[i]);


            int target_index = prefix_sum + n;


            if (first_occurrence[target_index] != -2) {

                int current_len = i - first_occurrence[target_index];
                max_len = max(max_len, current_len);
            } else {

                first_occurrence[target_index] = i;
            }
        }

        return max_len;

    }
};

