class Solution {
  public:
    int longestUniqueSubstr(string &s) {
        // code here
        vector<int> freq(26, 0);
        int cnt = 0;
        int n = s.length();

        int i = 0, j = 0;
        while(j < n) {
            freq[s[j] - 'a'] ++;

            while(freq[s[j] - 'a'] > 1) {
                freq[s[i] - 'a'] --;
                i ++;
            }

            cnt = max(cnt, j - i + 1);
            j ++;
        }

        return cnt;
    }
};

class Solution {
  public:
    int longestKSubstr(string &s, int k) {
        // code here
        int l = 0;
        int ans = -1;
        int distinctCount = 0;
        int freq[26] = {0};
        for(int r=0;r<s.length();r++){
            freq[s[r]-'a']++;
            if(freq[s[r]-'a']==1) distinctCount++;
            while(distinctCount > k){
                freq[s[l]-'a']--;
                if(freq[s[l]-'a'] == 0) distinctCount--;
                l++;
            }
            if(distinctCount == k){
                ans = max(ans, r-l+1);
            }
        }
        return ans;
    }
};

class Solution {
  public:
    int maxLength(string str) {
        // code here
        int ans = 0, n = str.length();
        stack<int> s;
        // let say dp[i] repreesent the longest valid substring ending at i i.e string having str[i] as its last character
        int dp[n];
        for(int i = 0; i<n; i++){
            if(str[i]=='('){
                s.push(i);
                dp[i] = 0;
            }
            else{
                if(!s.empty()){
                    int j = s.top();
                    s.pop();
                    int before_streak = 0;
                    if(j-1 >= 0) before_streak = dp[j-1];// to address ()().. to add any before streak
                    ans = max(ans,i-j+1+before_streak); // the range of i-j is entirely valid
                    // ((())) kind of things are addressed by i-j+1
                    dp[i] = i-j+1+before_streak;
                }
                else{
                   dp[i] = 0; 
                }
            }
        }
        return ans;
    }
};

class Solution {
  public:
    // Function to find the majority elements in the array
    vector<int> findMajority(vector<int>& arr) {
        int n=arr.size();
        if(n==1) return arr;
        vector<int> ans;
        int ele1=arr[0],ele2=arr[1],c1=0,c2=0;
        for(int i=2;i<n;i++){
            if(arr[i]==ele1){
                c1++;
            }
            else if(arr[i]==ele2){
                c2++;
            }
            else if(c1==0){
                ele1=arr[i];
                c1++;
            }
            else if(c2==0){
                ele2=arr[i];
                c2++;
            }
            else{
                c1--;
                c2--;
            }
        }
        c1=0,c2=0;
        for(int i=0;i<n;i++){
            if(arr[i]==ele1) c1++;
            else if(arr[i]==ele2) c2++;
        }
        if(c1>( n/3)) ans.push_back(ele1);
        if(c2> (n/3)) ans.push_back(ele2);
        sort(ans.begin(),ans.end());
        return ans;
    }
};

class Solution {
