        for(int i = 0; i < arr.size(); i++){
            if(count == 0){
                ans = arr[i];
            }
            if(arr[i] == ans){
                count++;
            }
            else if(arr[i] != ans){
                count--;
            }
        }
        count = 0;
        for(int i = 0; i < arr.size(); i++) {
