    bool check(double mid, vector<int>&arr, int k){
        int n=arr.size();
        int count=0;
        for(int i=1;i<n;i++){
            int dist=arr[i]-arr[i-1];
            if(dist<=mid){
                continue;
            }
            else{
                count+=int(dist/mid);
            }
        }
        return count<=k;
    }

    double findSmallestMaxDist(vector<int> &stations, int k) {
        // Code here
        int n=stations.size();
        double lo=0.0;
        double hi=0.0;
        for(int i=1;i<n;i++){
            if(hi<stations[i]-stations[i-1]){
                hi=stations[i]-stations[i-1];
            }
        }
        double ans=hi;
        while(hi-lo>1e-9){
            double mid= (hi-lo)/2.0 + lo;
            if(check(mid, stations, k)){
                ans=mid;
                hi=mid;
            }
            else{
                lo=mid;
            }
        }
        return ans;
    }
};

class Solution {
public:
    int minimizeDifference(int n, int k, vector<int> &arr) {
        vector<int> post_max(n), post_min(n);
        post_max[n - 1] = post_min[n - 1] = arr[n - 1];

        for(int i = n - 2; i >= 0; i--) {
            post_max[i] = max(arr[i], post_max[i + 1]);
            post_min[i] = min(arr[i], post_min[i + 1]);
        }

        int mini = arr[0], maxi = arr[0], res = post_max[k] - post_min[k];

        for(int i = 1; i < n - k; i++) {
            res = min(res, max(maxi, post_max[i + k]) - min(mini, post_min[i + k]));
            mini = min(mini, arr[i]);
            maxi = max(maxi, arr[i]);
        }

        res = min(res, maxi - mini);

        return res;
    }
};

