class Solution {
  public:
    long long donutsInTime(long long r, long long T) {
        // k = floor( (-1 + sqrt(1 + 8T/r)) / 2 )
        long double val = 1.0L + (8.0L * T) / r;
        long double k = (sqrt(val) - 1.0L) / 2.0L;
        return (long long)k;
    }

    int minTime(vector<int>& ranks, int n) {
        long long low = 0;
        long long mx = *max_element(ranks.begin(), ranks.end());
        long long high = mx * 1LL * n * (n + 1) / 2;   // safe upper bound

        while (low < high) {
            long long mid = (low + high) / 2;

            long long donuts = 0;
            for (long long r : ranks) {
                donuts += donutsInTime(r, mid);
                //if (donuts >= n) break;   // early stop
            }

            if (donuts >= n)
                high = mid;
            else
                low = mid + 1;
        }

        return (int)low;
    }
};

class Solution {
  public:
    int findMinCycle(int V, vector<vector<int>>& edges) {
        const int INF = 1e8;
        vector<vector<int>> dist(V, vector<int>(V, INF));
        vector<vector<int>> adj(V, vector<int>(V, INF)); 
        for (auto &e : edges) {
            int u = e[0], v = e[1], w = e[2];
            adj[u][v] = adj[v][u] = min(adj[u][v], w); 
            dist[u][v] = dist[v][u] = min(dist[u][v], w); 
        }

        for (int i = 0; i < V; ++i) dist[i][i] = 0;

        int minCycle = INF;

        for (int k = 0; k < V; ++k) {
            for (int i = 0; i < k; ++i) {
                for (int j = i + 1; j < k; ++j) {
                    if (dist[i][j] < INF && adj[i][k] < INF && adj[k][j] < INF) {
                        int cycleWeight = dist[i][j] + adj[i][k] + adj[k][j];
                        minCycle = min(minCycle, cycleWeight);
                    }
                }
            }
            for (int i = 0; i < V; ++i) {
                for (int j = 0; j < V; ++j) {
                    if (dist[i][k] < INF && dist[k][j] < INF) {
                        dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
                    }
                }
            }
        }

        return (minCycle == INF) ? -1 : minCycle;
    }
};

class Solution {
