class Solution {
  public:
    vector<int> reducePairs(vector<int>& v) {
        int n=v.size();
        stack<int>st;
        for(int i=0;i<n;i++)
        {
           if(st.empty())
           {
               st.push(v[i]);
               continue;
           }
           bool insert=1;
           while(!st.empty() && 1LL*v[i]*st.top()<0)
           {
               if(abs(v[i])<abs(st.top())) {insert=0;break;}
               else if(abs(v[i])==abs(st.top())) {st.pop();insert=0;break;}
               else st.pop();
           }
           if(insert) st.push(v[i]);
        }
        vector<int>ans;
        while(!st.empty()){ans.push_back(st.top()); st.pop();}
        reverse(ans.begin(),ans.end());
        return ans;

    }
};

class Solution {
  public:
    int minCost(vector<int> &keys, vector<int> &freq) {
        // code here
        int n=keys.size();

        vector<vector<int>> dp(n,vector<int>(n,0));
        vector<vector<int>> sum(n,vector<int>(n,0));

        for(int i=0;i<n; i++){

            sum[i][i]=freq[i];

            for(int j=i+1;j<n;j++){
                sum[i][j]=sum[i][j-1]+freq[j];
            }
        }


        for(int len=1;len<=n;len++){

            for(int i=0;i+len-1<n;i++){

                int j=i+len-1;

                if(i==j){
                    dp[i][j]=freq[i];
                    continue;
                }

                dp[i][j]=INT_MAX;

                for(int r=i;r<=j;r++){

                    int left=(r>i) ? dp[i][r-1] : 0;
                    int right=(r<j) ? dp[r+1][j] : 0;
                    dp[i][j]=min(dp[i][j], left + right + sum[i][j]);
                }
            }
        }

        return dp[0][n-1];
    }
};

class Solution{
    public:
    long long solve(int i, int n, int arr[], vector<vector<long long>>& dp) {
        if(i > n)
            return 0;
        if(dp[i][n] != -1)
            return dp[i][n];
        long long ans1 = arr[i] + min(solve(i + 1, n - 1, arr, dp), solve(i + 2, n, arr, dp));
        long long ans2 = arr[n] + min(solve(i + 1, n - 1, arr, dp), solve(i, n - 2, arr, dp));
        return dp[i][n] = max(ans1, ans2);
    }
    long long maximumAmount(int n, int arr[]){

        vector<vector<long long>> dp(n + 2, vector<long long>(n + 2, -1));
        return solve(0, n - 1, arr, dp);
    }
};

