        Node* reversalList(Node* head){
        Node* pre=NULL;
        Node* next=NULL;
        while(head!=NULL){
            next=head->next;
            head->next=pre;
            pre=head;
            head=next;
        }
        return pre;
    }
    //Function to check whether the list is palindrome.
    bool isPalindrome(Node *head)
    {
         if(head==NULL || head->next==NULL) return true;
        Node* slow=head;
        Node* fast=head;
        //Find middle element
        while(fast->next!=NULL && fast->next->next!=NULL){
            slow=slow->next;
            fast=fast->next->next;
        }

        slow->next=reversalList(slow->next);
        slow=slow->next;

        while(slow!=NULL){
            if(head->data!=slow->data)
                return false;
            head=head->next;
            slow=slow->next;
        }
        return true;  
    }
};

class Solution {
public:
    bool sentencePalindrome(string &s) {
        string cleaned = "";

        // Clean the input: retain only alphanumeric characters and convert to lowercase
        for (char c : s) {
            if (isalnum(c)) {
                cleaned += tolower(c);
            }
        }

        // Check if the cleaned string is a palindrome
        int left = 0, right = cleaned.size() - 1;
        while (left < right) {
            if (cleaned[left] != cleaned[right]) {
                return false;
            }
            left++;
            right--;
        }

        return true;
    }
};

