class Solution {
  public:
    void segregate0and1(vector<int> &arr) {

        int n = arr.size();
        int i =0;
        int j =n-1;
        while(j> i){
            if(arr[i]==1 && arr[j]==0){
                swap(arr[j],arr[i]);
                i++;
                j--;
            }
            else if(arr[i] ==1 && arr[j]== 1){
                j--;
            }
            else if(arr[i] ==0 && arr[j]== 0){
                i++;
            }
            else{
                i++;
                j--;
            }
        }
    }
};

class Solution{ 
public: 
    int solve(int i,int j,int n,int m,vector<vector<int>>&dp) 
    { 
        if(j==0) 
            return 1; 
        if(i>m) 
            return 0; 
        if(dp[i][j]!=-1) 
            return dp[i][j]; 
        int take=solve(i*2,j-1,n,m,dp); 
        int not_take=solve(i+1,j,n,m,dp); 
        return dp[i][j]=take+not_take; 
    } 
    int numberSequence(int m, int n){ 
        vector<vector<int>>dp(m+1,vector<int>(n+1,-1)); 
        return solve(1,n,n,m,dp); 
    } 
};

class Solution
{
    void inorder(Node *root, vector<int> &store){
        if(root == NULL)
            return;

        inorder(root->left, store);
        store.push_back(root->data);
        inorder(root->right, store);
    }

    public:
    //Function to serialize a tree and return a list containing nodes of tree.
    vector<int> serialize(Node *root) 
    {
        vector<int> str;
        inorder(root, str);
        return str;
    }

    //Function to deserialize a list and construct the tree.
    Node * deSerialize(vector<int> &A)
    {
        int n = A.size();
        Node *root = new Node(A[0]);

        for(int i=1; i<n; i+=2){
            Node *newRoot = new Node(A[i]);
            newRoot->left = root;
            if(i+1 < n){
                newRoot->right = new Node(A[i+1]);
            }
            root = newRoot;
        }
        return root;
    }

};

