class Solution {
  public:
    vector<int> shortestPath(vector<vector<int>>& edges, int N,int M, int src){
        vector<int> adj[N];
        for(auto it : edges)
        {
            adj[it[0]].push_back(it[1]);
            adj[it[1]].push_back(it[0]);
        }

        vector<int> dist(N,-1);
        queue<int> q;
        dist[src] = 0;
        q.push(src);
        while(!q.empty())
        {
            int node = q.front();
            q.pop();
            for(auto it :adj[node])
            {
                if(dist[it]==-1)
                {
                    dist[it] = dist[node]+1;
                    q.push(it);
                }
            }
        }

        return dist;
    }
};

class Solution { 
  public: 
    vector<int> shortestPath(int V, int m, vector<vector<int>>& edges) { 
        unordered_map<int,list<pair<int,int>>>adj; 
        for(auto&it:edges){ 
            int u=it[0]; 
            int v=it[1]; 
            int weight=it[2]; 
            adj[u].push_back({v,weight}); 
            adj[v].push_back({u,weight}); 
        } 

        vector<int>visited(V+1,0); 
        vector<int>dist(V+1,INT_MAX); 
        dist[1]=0; 
        priority_queue<pair<int,int>,vector<pair<int,int>>,greater<pair<int,int>>>pq;  
        pq.push({0,1}); 
        vector<int>parent(V+1,-1); 

        while(!pq.empty()){ 
            int node=pq.top().second; 
            pq.pop(); 

            if(!visited[node]){ 
                visited[node]=true; 
                for(auto v:adj[node]){ 
                    int nbr=v.first; 
                    int weight=v.second; 
                    if(dist[nbr]>dist[node]+weight){ 
                        dist[nbr]=dist[node]+weight; 
                        pq.push({dist[nbr],nbr}); 
                        parent[nbr]=node; 
                    } 
                } 
            } 
        } 

        if(parent[V]==-1)return {-1}; 
        vector<int>path; 
        int t=V; 
        while(t!=-1){ 
         path.push_back(t); 
         t=parent[t]; 
        } 
        path.push_back(dist[V]); 
        reverse(path.begin(),path.end()); 
        return path; 
    } 
};

class Solution{    
public: 
   void SieveOfEratosthenes(int n, vector<bool> &prime) 
  { 
    for (int p = 2; p * p <= n; p++) 
    { 
      if (prime[p] == true) 
      { 
        for (int i = p * p; i <= n; i += p) 
          prime[i] = false; 
      } 
    } 
  } 
  int solve(int Num1, int Num2) 
  { 
    vector<bool> prime(10000, 1); 
    SieveOfEratosthenes(9999, prime); 
    int ans = 0; 
    queue<int> q; 
    q.push(Num1); 
    while (!q.empty()) 
    { 
      int sz = q.size(); 
      for (int i = 0; i < sz; i++) 
      { 
        int val = q.front(); 
        q.pop(); 
        if (val == Num2) 
          return ans; 
        string s = to_string(val); 
        for (int j = 0; j < 4; j++) 
        { 
          char c = s[j]; 
          for (int k = 0; k < 10; k++) 
          { 
            if (k == 0 && j == 0) 
              continue; 
            s[j] = '0' + k; 
            int temp = stoi(s); 
            if (prime[temp]) 
            { 
              q.push(temp); 
              prime[temp] = 0; 
            } 
          } 
          s[j] = c; 
        } 
      } 
      ans++; 
    } 
  } 
};

