class Solution {
  public:
    // Function to find the smallest positive number missing from the array.
    int missingNumber(vector<int> &arr) {
        bool flag = false;
        int n = arr.size();

        for (int i = 0; i < n; i++)  {
            if (arr[i] == 1)
                flag = true;

            if (arr[i] < 1 or arr[i] > n)
                arr[i] = 1;
        }

        if (not flag)
            return 1;

        for (int i = 0; i < n; i++)  {
            int id = abs(arr[i]);
            arr[id - 1] = -1*abs(arr[id-1]);
        }

        for (int i = 0; i < n; i++)  {
            if (arr[i] > 0)
                return i + 1;
        }

        return n + 1;
    }
};

class Solution {
  public:
    string minWindow(string &s, string &p) {
        // code here
        int n = s.size();
        int m = p.size();

        vector<int> hash(26);
        for(int i=0;i<m;i++){
            hash[p[i]-'a']++;
        }

        int l=0,r=0,mini=INT_MAX,ind=-1;
        int cnt=0;

        for(;r<n;r++){
            if(hash[s[r]-'a']>0) cnt++;
            hash[s[r]-'a']--;

            while(cnt==m){
                if(r-l+1<mini){
                    mini=r-l+1;
                    ind=l;
                }

                hash[s[l]-'a']++;
                if(hash[s[l]-'a']>0) cnt--;
                l++;
            }
        }

        if(mini==INT_MAX || ind==-1) return "";

        return s.substr(ind,mini);
    }
};

class Solution
{
    public:
    //Function to find the smallest window in the string s consisting
    //of all the characters of string p.
    string smallestWindow (string s, string p)
    {
        // define string size; and used letters count
        int n = p.size();
        int countS[26] = {0};
        int countP[26] = {0};
        char chP, chS;

        // fill counts p with letters counts
        for(int i=0; i<n; i++)
        {
            char chP = p[i] - 'a';
            countP[chP]++;
        }

        // iMin, lenMin - starting point and length of minimum substring
        int iMin = -1;
        int lenMin = s.size() + 1;
        // i starting position of checked substring
        int i = 0;
        // count charachters in s and in p
        int count = 0;

        // loop throug s characters, increasing end point of the substring
        for(int j=0; j<s.size(); j++)
        {
            chS = s[j] - 'a';
            // when characters match; countP should be greater than countS
            if(countP[chS] > countS[chS])
            {
                count++;
            }
            countS[chS]++;

            // when count reaches length of p, start increase i
            if(count == n)
            {
                // increase i as much as possible
                char ch = s[i] - 'a';
                while(countS[ch] > countP[ch])
                {
                    countS[ch]--;
                    i++;
                    ch = s[i] - 'a';
                }
                // check substring position
                int len = j - i + 1;
                if(len < lenMin)
                {
                    iMin = i;
                    lenMin = len;
                }
            }
        }

        // update the results
        if(iMin > -1)
       {
            return s.substr(iMin, lenMin);
        }
        else
        {
            return "-1";
        }
    }
};

class Solution {
  public:
    void sort012(vector<int>& arr) {
    int i = 0;
    int j = 0;
    int k = arr.size() - 1;

    while (j <= k) {
        switch (arr[j]) {
            case 0:
                swap(arr[i], arr[j]);
                ++i;
                ++j;
                break;
            case 1:
                ++j;
                break;
            case 2:
                swap(arr[j], arr[k]);
                --k;
                break;
        }
    }
}
};

