class Solution {
  public:
    // Complete this function
    // Function to sort the array according to frequency of elements.
    vector<int> sortByFreq(vector<int>& arr) {
    unordered_map<int, int> mp;
    for(int num : arr) 
        mp[num]++;

    vector<pair<int, int>> freqVec;
    for(auto& it : mp) {
        freqVec.push_back({it.second, it.first});
    }

    // Sort by frequency descending, and by value ascending
    sort(freqVec.begin(), freqVec.end(), [](pair<int, int>& a, pair<int, int>& b) {
        if (a.first == b.first) 
            return a.second < b.second; // If frequencies are the same, sort by value ascending
        return a.first > b.first; // Sort by frequency descending
    });

    vector<int> result;
    for(auto& p : freqVec) {
        result.insert(result.end(), p.first, p.second);
    }

    return result;
}
};

class Solution {
  public:
    vector<vector<int>> spiralFill(int n, int m, vector<int> &arr) {
        vector<vector<int>> matrix(n, vector<int>(m, 0));

        int top = 0, bottom = n - 1, left = 0, right = m - 1;
        int index = 0; 

        while (top <= bottom && left <= right) {

            for (int j = left; j <= right && index < arr.size(); j++) {
                matrix[top][j] = arr[index++];
            }
            top++;


            for (int i = top; i <= bottom && index < arr.size(); i++) {
                matrix[i][right] = arr[index++];
            }
            right--;


            for (int j = right; j >= left && index < arr.size(); j--) {
                matrix[bottom][j] = arr[index++];
            }
            bottom--;


            for (int i = bottom; i >= top && index < arr.size(); i--) {
                matrix[i][left] = arr[index++];
            }
            left++;
        }

        return matrix;
    }
};

class Solution {
