class Solution {
public:
    vector<int> findSplit(vector<int>& arr) {
        int total_sum = 0;
        for (int num : arr) {
            total_sum += num;
        }

        if (total_sum % 3 != 0) {
            return {-1, -1};
        }

        int target_sum = total_sum / 3;
        int current_sum = 0;
        int first_index = -1, second_index = -1;
        int n = arr.size();

        for (int i = 0; i < n; i++) {
            current_sum += arr[i];

            if (current_sum == target_sum && first_index == -1) {
                first_index = i;
            }

            if (current_sum == 2 * target_sum && first_index != -1) {
                second_index = i;
                break;
            }
        }

        if (first_index != -1 && second_index != -1) {
            int last_part_sum = 0;
            for (int i = second_index + 1; i < n; i++) {
                last_part_sum += arr[i];
            }
            if (last_part_sum == target_sum) {
                return {first_index, second_index};
            }
        }

        return {-1, -1};
    }
};

class Solution { 
  public: 
    bool solve(int arr[], int N, int K, int mid) 
    { 
        int sum = 0; 
        for(int i = 0; i < N; i++) 
        { 
            if(arr[i] > mid) 
                return false; 
            sum += arr[i]; 
            if(sum > mid) 
            { 
                K--; 
                sum = arr[i]; 
            } 
        } 
        if(K >= 1) 
            return true; 
        return false; 
    } 
    int splitArray(int arr[] ,int N, int K) { 
        int sum = 0; 
        for(int i = 0; i < N; i++) 
            sum += arr[i]; 
        int low = 0, high = sum; 
        int ans = sum; 
        while(low <= high) 
        { 
            int mid = (low + high) / 2; 
            if(solve(arr, N, K, mid)) 
            { 
                ans = mid; 
                high = mid - 1; 
            } 
            else  
                low = mid + 1; 
        } 
        return ans; 
    } 
};

class Solution {
  public:
    // Function to split a linked list into two lists alternately

    vector<Node*> alternatingSplitList(struct Node* head) {
        if(!head->next) return {head, NULL};

        Node* head1 = head, *head2 = head->next;
        Node* tail1 = head1, *tail2 = head2;

        while(tail2){

            tail1->next = tail2->next;
            tail1 = tail1->next;

            if(tail1){
                tail2->next = tail1->next;
            }
            tail2 = tail2->next;
        }

        return {head1, head2};
    }
};

