class Solution {
  public:
    int floorSqrt(int n) {
        int start = 0, end = n, ans = 0;

        while (start <= end) {
            int mid = start + (end - start) / 2;


            if (mid * mid == n) {
                return mid;
            }

            else if (mid * mid < n) {
                ans = mid;
                start = mid + 1;
            }

            else {
