class Solution {
  public:
    vector<int> stableMarriage(vector<vector<int>> &men, vector<vector<int>> &women) {
        // code here
        int n = men.size();

        // Flattened rank array (cache friendly)
        vector<int> rank(n * n);
        for (int w = 0; w < n; w++) {
            for (int i = 0; i < n; i++) {
                rank[w * n + women[w][i]] = i;
            }
        }

        vector<int> manPartner(n, -1), womanPartner(n, -1), next(n, 0);

        vector<int> freeMen(n);
        int top = n;
        for (int i = 0; i < n; i++) freeMen[i] = i;

        while (top) {
            int m = freeMen[--top];
            int w = men[m][next[m]++];

            int current = womanPartner[w];

            if (current == -1 || rank[w * n + m] < rank[w * n + current]) {
                womanPartner[w] = m;
                manPartner[m] = w;

                if (current != -1)
                    freeMen[top++] = current;
            } else {
                freeMen[top++] = m;
            }
        }

        return manPartner;
    }
};

class Solution {
  public:
    int robLinear(vector<int>& nums) {
        int n = nums.size();
        if (n == 1) return nums[0];

        int prev2 = 0, prev1 = 0;
        for (int num : nums) {
            int temp = max(prev1, prev2 + num);
            prev2 = prev1;
            prev1 = temp;
        }
        return prev1;
    }

    int maxValue(vector<int>& arr) {
        int n = arr.size();
        if (n == 1) return arr[0];

        vector<int> case1(arr.begin(), arr.end() - 1); 
        vector<int> case2(arr.begin() + 1, arr.end()); 

        return max(robLinear(case1), robLinear(case2));
    }
};

