class Solution {
public:
    bool checkSorted(vector<int>& arr) {

        // code here.
           int n = arr.size();
        int swapCnt = 0;

        for(int i=0;i<n;i++){
            // if curr element is correct position then continue.
            if(arr[i] == i+1) continue;

            // if curr element is not correct position then try to 
            // do correct position using swap.
            while(arr[i] != i+1){
                swap(arr[arr[i] - 1],arr[i]);
                swapCnt++;
            }
        }

        // arr is already swap or swapCnt equal to 2.
        if(swapCnt == 2 || swapCnt == 0) return true;
        return false;

    }
};

class Solution {
  public:

    int pour(int fromCap, int toCap, int d) {
        int from = fromCap;
        int to = 0;
        int step = 1; // fill from jug

        while (from != d && to != d) {
            int temp = min(from, toCap - to);

            to += temp;
            from -= temp;
            step++;

            if (from == d || to == d)
                break;

            if (from == 0) {
                from = fromCap;
                step++;
            }

            if (to == toCap) {
                to = 0;
                step++;
            }
        }

        return step;
    }

    int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }

    int minSteps(int m, int n, int d) {
        if (d > max(m, n)) return -1;

        if (d % gcd(m, n) != 0) return -1;

        // try both directions
        return min(pour(m, n, d), pour(n, m, d));
    }
};

