class Solution:
    def checkCover(self, n, k, m, adj):
        sett = (1 << k) - 1
        limit = (1 << n)
        while (sett < limit):
            visited = [[False for i in range(n+1)] for j in range(n+1)]
            cnt = 0
            j = 1
            v = 1
            while(j < limit):
                if (sett & j):
                    for k in range(1, n+1):
                        if(adj[v][k] and (not visited[v][k])):
                            visited[v][k] = 1
                            visited[k][v] = 1
                            cnt = cnt + 1
                j = j << 1
                v = v + 1
            if (cnt == m):
                return True
            c = sett & -sett
            r = sett + c
            sett = (((r ^ sett) >> 2) // c) | r
        return False

    def vertexCoverHelper(self, adj, n, m):
        low = 1
        high = n
        while (high > low):
            mid = (low + high) >> 1
            if(self.checkCover(n, mid, m, adj) == False):
                low = mid + 1
            else:
                high = mid
        return low

    def vertexCover(self, n : int, edges : List[List[int]]) -> int:
        m = len(edges)
        rows, cols = n+1, n+1
        adj = [[0 for i in range(cols)] for j in range(rows)]
        for i in range(m):
            adj[edges[i][0]][edges[i][1]] = 1
            adj[edges[i][1]][edges[i][0]] = 1
        return self.vertexCoverHelper(adj, n, m)

class Solution{
  public:
    vector <int> verticalSum(Node *root) {
        vector<int> res;
        map<int,int> mp;
        queue<pair<Node*,int>> q;
        q.push({root,0});
        while(!q.empty()){
            Node * node = q.front().first;
            int line = q.front().second;
            q.pop();

            mp[line] += node->data;

            if(node->left)
                q.push({node->left,line-1});
            if(node->right)
                q.push({node->right,line+1});
        }
        for(auto i : mp){
            res.push_back(i.second);
        }
        return res;
    }
};

class Solution {
public:
    vector<vector<int>> verticalOrder(Node *root) {
        vector<vector<int>> ans;
        if(root == NULL) return ans;

        map<int, vector<int>> mp; // HD -> nodes
        queue<pair<Node*, int>> q;

        q.push({root, 0});

        while(!q.empty()){
            auto it = q.front();
            q.pop();

            Node* node = it.first;
            int hd = it.second;

            mp[hd].push_back(node->data);

            if(node->left)
                q.push({node->left, hd - 1});

            if(node->right)
                q.push({node->right, hd + 1});
        }

        for(auto it : mp){
            ans.push_back(it.second);
        }

        return ans;
    }
};

class Solution {
