        if(root==NULL)
        return;
        mini=min(mini,i);
        maxi=max(maxi,i);
        solve(root->left,mini,maxi,i-1);
        solve(root->right,mini,maxi,i+1);
    }
    int verticalWidth(Node* root) {
        int mini=INT_MAX;
        int maxi=INT_MIN;
        solve(root,mini,maxi,0);
        return abs(mini)+abs(maxi)+1;
    }
};

class Solution {
  public:
    int minCost(vector<vector<int>> &costs) {
        // code here
        int n=costs.size();
        int k=costs[0].size();

        if(k==1 && n!=1) 
            return -1;

        vector<vector<int>> dp(n,vector<int>(k,-1));
        for(int i=0;i<k;i++) 
            dp[0][i]=costs[0][i];

        for(int i=1;i<n;i++){
            int mincost=INT_MAX;
            int minidx=-1;
// Finding min element and its index till wall[i]

            for(int j=0;j<k;j++)
                if(dp[i-1][j]<mincost){
                    mincost=dp[i-1][j];
                    minidx=j;
                }

// Finding 2nd least element which helps in computing the

// min element for wall [i] incase the index is minidx

            int mincost2=INT_MAX;
            for(int j=0;j<k;j++)
                if(j!=minidx && dp[i-1][j]<mincost2)
                    mincost2=dp[i-1][j];

            for(int j=0;j<k;j++){
                if(j==minidx)
                    dp[i][j]=mincost2+costs[i][j];
                else
                    dp[i][j]=mincost+costs[i][j];
            }
        }

        int ans=INT_MAX;
        for(int i=0;i<k;i++) 
            ans=min(ans,dp[n-1][i]);
        return ans;   
    }
};

class Solution{
    public:
    int min_sprinklers(int gallery[], int n)
    {
        // code here
        vector<pair<int,int>>v;
        for(int i=0;i<n;i++){
            if(gallery[i]!=-1){
                v.push_back({i-gallery[i], i+gallery[i]});
            }
        }
        int m=v.size();
        sort(v.begin(), v.end());
        int target=0, i=0, ans=0;
        while(target<n && i<m){
            if(v[i].first > target) return -1;

            int maxi=v[i].second; i++;
            while(i<m && v[i].first<=target){
                maxi=max(maxi, v[i].second);
                i++;
            }
            target=maxi+1;
            ans++;
        }
        if(target<n-1){
            return -1;
        }
        else{
            return ans;
        }
    }
};

class Solution {
  public:
    int wildCard(string pattern, string str) {
        int n = pattern.size(), m = str.size(); int dp[n+2][m+2];
        memset(dp, 0, sizeof(dp)); dp[n][m] = 1;
        for ( int i = n; i>=0; i-- ){
            for ( int j = m; j>=0; j-- ){
                if ( pattern[i] == str[j] || pattern[i] == '?' ) {
                    dp[i][j] |= dp[i+1][j+1];
                }
                if ( pattern[i] == '*' ){
                    dp[i][j] |= dp[i+1][j+1];
                    dp[i][j] |= dp[i][j+1];
                    dp[i][j] |= dp[i+1][j];
                } 
            }
        } return dp[0][0];
    }
};

class Solution {
  public:
    int fun(int i, string &s, set<string> &st, vector<int> &dp){
        if(i==s.size())
            return 1;
        if(dp[i] != -1)
            return dp[i];

        string temp = "";
        for(int j=i;j<s.size();j++){
            temp+=s[j];
            if(st.find(temp) != st.end()){
                if(fun(j+1, s, st, dp))
                    return dp[i]=1;
            }
        }
        return dp[i]=0;    
    }

    int wordBreak(string &s, vector<string> &dic) {
        // code here
        int n = s.size();
        vector<int> dp(n+1, -1);
        set<string> st;
        for(auto z : dic){
            st.insert(z);
        }

        return fun(0, s, st, dp);
    }
};

class TrieNode {
    TrieNode[] children;
    boolean isEndOfWord;

    public TrieNode() {
        children = new TrieNode[26];
        isEndOfWord = false;
    }
}

class Solution {
    static TrieNode root;

    public static int wordBreak(int n, String s, ArrayList<String> dictionary) {
        // Initialize the root of the trie
        root = new TrieNode();
        // Build the trie 
        for (String word : dictionary) {
            insert(word);
        }
        // Check if the string can be segmented using the trie
        return canSegmentString(s, root) ? 1 : 0;

    }

    static boolean canSegmentString(String s, TrieNode root) {
        int n = s.length();
        if (n == 0)
            return true;
        TrieNode current = root;
        for (int i = 0; i < n; i++) {
            char ch = s.charAt(i);
            if (current.children[ch - 'a'] == null)
                return false;
            current = current.children[ch - 'a'];
            if (current.isEndOfWord && canSegmentString(s.substring(i + 1), root))
                return true;
        }
        return false;
    }

    static void insert(String word) {
        TrieNode current = root;
        for (char ch : word.toCharArray()) {
            int index = ch - 'a';
            if (current.children[index] == null)
                current.children[index] = new TrieNode();
            current = current.children[index];
        }
        current.isEndOfWord = true;
    }
}

class Solution {
  public:

    int n,m;

    int r[4]={0,0,1,-1};
    int c[4]={1,-1,0,0};

    bool isValid(int x,int y)
    {
        return x>=0 && y>=0 && x<n && y<m;
    }

    bool dfs(int i,int x,int y,vector<vector<char>> &mat,string &s)
    {
        if(i==s.size())
            return 1;
        char temp=mat[x][y];
        mat[x][y]='(';
        for(int k=0;k<4;k++)
        {
            int nx=x+r[k];
            int ny=y+c[k];
            if(isValid(nx,ny) && s[i]==mat[nx][ny])
                if(dfs(i+1,nx,ny,mat,s))
                    return 1;
        }
        mat[x][y]=temp;
        return 0;
    }


    bool isWordExist(vector<vector<char>> &mat, string &s) {
        n=mat.size(),m=mat[0].size();
        for(int i=0;i<n;i++)
            for(int j=0;j<m;j++)
                if(mat[i][j]==s[0])
                    if(dfs(1,i,j,mat,s))
                        return 1;
        return 0;
    }
};

struct Node *insert(struct Node *head, int data) {
    Node* newnode=new Node(data);
    newnode->npx=XOR(NULL,head);
    if(head!=NULL){
        Node* temp=XOR(head->npx,NULL);
        head->npx=XOR(temp,newnode);
    }
    head=newnode;
    return head;
}

vector<int> getList(struct Node *head) {
    vector<int>ans;
    Node* prev=NULL;
    while(head!=NULL){
        ans.push_back(head->data);
        Node* temp=head;
        head=XOR(prev,head->npx);
        prev=temp;
    }
    return ans;
}

